import json
b=json.load(open('baseline-packages.json'))
a=json.load(open('after-cpm-packages.json'))
def extract(data):
    pkgs={}
    for p in data['projects']:
        name=p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw.get('topLevelPackages',[]):
                pkgs[(name,pkg['id'])]=(pkg['requestedVersion'],pkg['resolvedVersion'])
    return pkgs
bp,ap=extract(b),extract(a)
print('Differences:')
diff=False
for k in sorted(set(list(bp.keys())+list(ap.keys()))):
    bv=bp.get(k)
    av=ap.get(k)
    if bv!=av:
        diff=True
        print(f'  {k}: {bv} -> {av}')
if not diff:
    print('  None - fully version-neutral')
"

